script:
// Лаборатория совместимости — standalone widget, launched as a single ExtBlocks JS script block.
// Runs as the body of an async function (ExtBlocks evals it inside `(async () => { ... })()`).
// Play happens inside a Popup; the chat stays clean until "Завершить сессию".
// In-widget text uses generateRaw with our OWN system prompt + a tiny scene digest, so the model
// READS the RP but writes a clean analytical report (NO roleplay, no comics/weather injects, fewer tokens).
// On finish the character's reaction is generated in isolation too (in-character but ONLY about the results)
// and committed to chat via addOneMessage; an optional in-widget discussion can be played out first.
// Math is deterministic JS; charts (destiny-matrix octagrams, natal synastry wheel, donut) are drawn as SVG.
// State persists in chat metadata; results are cached (no needless re-generation). Astro/planet glyphs are
// forced to text presentation (U+FE0E) so the OS does not render them as colorful emoji.

const ctx = SillyTavern.getContext();

// === Лаборатория совместимости живёт в «волшебной палочке» (#extensionsMenu). ===
// Сам виджет открывается функцией window.__clabOpen — её вызывает пункт меню (см. installWand внизу файла).
// Блок при срабатывании НЕ открывает попап, а лишь идемпотентно вешает пункт меню. Никаких Quick Reply.
window.__clabOpen = async function () {
if (ctx.characterId === undefined && !ctx.groupId) {
    toastr.warning('[Лаборатория] Сначала открой чат с персонажем.');
    return;
}

// ===== MATH START =====
const RAD = Math.PI / 180;
const SIGNS = ['Овен','Телец','Близнецы','Рак','Лев','Дева','Весы','Скорпион','Стрелец','Козерог','Водолей','Рыбы'];
const SIGN_GLYPH = { 'Овен':'♈','Телец':'♉','Близнецы':'♊','Рак':'♋','Лев':'♌','Дева':'♍','Весы':'♎','Скорпион':'♏','Стрелец':'♐','Козерог':'♑','Водолей':'♒','Рыбы':'♓' };
const ARCANA = ['','Маг','Верховная Жрица','Императрица','Император','Иерофант','Влюблённые','Колесница','Сила','Отшельник','Колесо Фортуны','Справедливость','Повешенный','Смерть','Умеренность','Дьявол','Башня','Звезда','Луна','Солнце','Суд','Мир','Шут'];
const ELEMENT_OF = { 'Овен':'огонь','Лев':'огонь','Стрелец':'огонь','Телец':'земля','Дева':'земля','Козерог':'земля','Близнецы':'воздух','Весы':'воздух','Водолей':'воздух','Рак':'вода','Скорпион':'вода','Рыбы':'вода' };
const PLANET_GLYPH = { 'Солнце':'☉','Луна':'☽','Меркурий':'☿','Венера':'♀','Марс':'♂','Юпитер':'♃','Сатурн':'♄' };
const TAROT_CARDS = [['Шут','RWS_Tarot_00_Fool.jpg'],['Маг','RWS_Tarot_01_Magician.jpg'],['Верховная Жрица','RWS_Tarot_02_High_Priestess.jpg'],['Императрица','RWS_Tarot_03_Empress.jpg'],['Император','RWS_Tarot_04_Emperor.jpg'],['Иерофант','RWS_Tarot_05_Hierophant.jpg'],['Влюблённые','RWS_Tarot_06_Lovers.jpg'],['Колесница','RWS_Tarot_07_Chariot.jpg'],['Сила','RWS_Tarot_08_Strength.jpg'],['Отшельник','RWS_Tarot_09_Hermit.jpg'],['Колесо Фортуны','RWS_Tarot_10_Wheel_of_Fortune.jpg'],['Справедливость','RWS_Tarot_11_Justice.jpg'],['Повешенный','RWS_Tarot_12_Hanged_Man.jpg'],['Смерть','RWS_Tarot_13_Death.jpg'],['Умеренность','RWS_Tarot_14_Temperance.jpg'],['Дьявол','RWS_Tarot_15_Devil.jpg'],['Башня','RWS_Tarot_16_Tower.jpg'],['Звезда','RWS_Tarot_17_Star.jpg'],['Луна','RWS_Tarot_18_Moon.jpg'],['Солнце','RWS_Tarot_19_Sun.jpg'],['Суд','RWS_Tarot_20_Judgement.jpg'],['Мир','RWS_Tarot_21_World.jpg']];

function norm(x) { x = x % 360; return x < 0 ? x + 360 : x; }
function signOf(lon) { return SIGNS[Math.floor(norm(lon) / 30)]; }
function digitSum(s) { let t = 0; for (const ch of String(s)) if (ch >= '0' && ch <= '9') t += +ch; return t; }
function reduceKeepMasters(n) { while (n > 9 && n !== 11 && n !== 22 && n !== 33) n = digitSum(n); return n; }
function lifePath(d, mo, y) { return reduceKeepMasters(digitSum(d) + digitSum(mo) + digitSum(y)); }
function r22(n) { while (n > 22) n = digitSum(n); return n; }
function matrixOf(d, mo, y) { const A = r22(d); const B = r22(mo); const C = r22(digitSum(y)); const core = r22(A + B + C); const mission = r22(A + B + C + core); return { A, B, C, core, mission }; }
const ZBOUND = [[19,'Козерог','Водолей'],[18,'Водолей','Рыбы'],[20,'Рыбы','Овен'],[19,'Овен','Телец'],[20,'Телец','Близнецы'],[20,'Близнецы','Рак'],[22,'Рак','Лев'],[22,'Лев','Дева'],[22,'Дева','Весы'],[22,'Весы','Скорпион'],[21,'Скорпион','Стрелец'],[21,'Стрелец','Козерог']];
function zodiacOf(d, mo) { const b = ZBOUND[mo - 1]; return d <= b[0] ? b[1] : b[2]; }
function jdNoon(y, mo, d) { const a = Math.floor((14 - mo) / 12); const yy = y + 4800 - a; const mm = mo + 12 * a - 3; return d + Math.floor((153 * mm + 2) / 5) + 365 * yy + Math.floor(yy / 4) - Math.floor(yy / 100) + Math.floor(yy / 400) - 32045; }
const ELEMS = {
  mercury: [0.38709927,0.20563593,7.00497902,252.25032350,77.45779628,48.33076593,0.00000037,0.00001906,-0.00594749,149472.67411175,0.16047689,-0.12534081],
  venus:   [0.72333566,0.00677672,3.39467605,181.97909950,131.60246718,76.67984255,0.00000390,-0.00004107,-0.00078890,58517.81538729,0.00268329,-0.27769418],
  earth:   [1.00000261,0.01671123,-0.00001531,100.46457166,102.93768193,0.0,0.00000562,-0.00004392,-0.01294668,35999.37244981,0.32327364,0.0],
  mars:    [1.52371034,0.09339410,1.84969142,-4.55343205,-23.94362959,49.55953891,0.00001847,0.00007882,-0.00813131,19140.30268499,0.44441088,-0.29257343],
  jupiter: [5.20288700,0.04838624,1.30439695,34.39644051,14.72847983,100.47390909,-0.00011607,-0.00013253,-0.00183714,3034.74612775,0.21252668,0.20469106],
  saturn:  [9.53667594,0.05386179,2.48599187,49.95424423,92.59887831,113.66242448,-0.00125060,-0.00050991,0.00193609,1222.49362201,-0.41897216,-0.28867794]
};
function helio(name, T) {
  const e0 = ELEMS[name];
  const a = e0[0] + e0[6] * T, ec = e0[1] + e0[7] * T, inc = (e0[2] + e0[8] * T) * RAD;
  const L = e0[3] + e0[9] * T, vp = e0[4] + e0[10] * T, om = e0[5] + e0[11] * T;
  const M = norm(L - vp) * RAD;
  let E = M;
  for (let i = 0; i < 10; i++) E = M + ec * Math.sin(E);
  const xv = a * (Math.cos(E) - ec), yv = a * Math.sqrt(1 - ec * ec) * Math.sin(E);
  const w = (vp - om) * RAD, O = om * RAD;
  const x = (Math.cos(w) * Math.cos(O) - Math.sin(w) * Math.sin(O) * Math.cos(inc)) * xv + (-Math.sin(w) * Math.cos(O) - Math.cos(w) * Math.sin(O) * Math.cos(inc)) * yv;
  const y = (Math.cos(w) * Math.sin(O) + Math.sin(w) * Math.cos(O) * Math.cos(inc)) * xv + (-Math.sin(w) * Math.sin(O) + Math.cos(w) * Math.cos(O) * Math.cos(inc)) * yv;
  return [x, y];
}
function natalAt(y, mo, d) {
  const T = (jdNoon(y, mo, d) - 2451545.0) / 36525.0;
  const dd = jdNoon(y, mo, d) - 2451545.0;
  const e = helio('earth', T);
  const out = {};
  out['Солнце'] = signOf(Math.atan2(-e[1], -e[0]) / RAD);
  const map = { 'Меркурий': 'mercury', 'Венера': 'venus', 'Марс': 'mars', 'Юпитер': 'jupiter', 'Сатурн': 'saturn' };
  for (const ru in map) { const p = helio(map[ru], T); out[ru] = signOf(Math.atan2(p[1] - e[1], p[0] - e[0]) / RAD); }
  const Lm = 218.316 + 13.176396 * dd;
  const Mm = (134.963 + 13.064993 * dd) * RAD;
  const Ms = (357.529 + 0.98560028 * dd) * RAD;
  const D = (297.8502 + 12.19074912 * dd) * RAD;
  out['Луна'] = signOf(Lm + 6.289 * Math.sin(Mm) + 1.274 * Math.sin(2 * D - Mm) + 0.658 * Math.sin(2 * D) - 0.186 * Math.sin(Ms) - 0.059 * Math.sin(2 * Mm - 2 * D) - 0.057 * Math.sin(Mm - 2 * D + Ms));
  return out;
}
function elementScore(s1, s2) {
  if (s1 === s2) return 88;
  const e1 = ELEMENT_OF[s1], e2 = ELEMENT_OF[s2];
  if (e1 === e2) return 84;
  const pair = [e1, e2].sort().join('+');
  const table = { 'воздух+огонь': 80, 'вода+земля': 80, 'земля+огонь': 56, 'вода+огонь': 52, 'вода+воздух': 60, 'воздух+земля': 55 };
  return table[pair] || 60;
}
function numerologyScore(n1, n2) {
  if (n1 === n2) return 90;
  let s = 92 - Math.abs(n1 - n2) * 6;
  if (n1 === 11 || n1 === 22 || n1 === 33 || n2 === 11 || n2 === 22 || n2 === 33) s += 4;
  return Math.max(42, Math.min(s, 96));
}
function clampPct(n) { return Math.max(0, Math.min(99, Math.round(n))); }
// ===== MATH END =====

// ---------- helpers ----------
const TX = '︎'; // text-presentation selector: kills emoji rendering of ♈ ☉ ♀ ♡ …
const glyph = (g) => (g ? g + TX : '');
const subst = (s) => ctx.substituteParams(String(s));
function parseDate(str) {
  const m = String(str || '').match(/(\d{1,2})[.\/-](\d{1,2})[.\/-](\d{4})/);
  if (!m) return null;
  const d = +m[1], mo = +m[2], y = +m[3];
  if (d < 1 || d > 31 || mo < 1 || mo > 12 || y < 1000 || y > 2100) return null;
  return { d, mo, y };
}
function esc(s) { return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;'); }
function mdLite(text) {
  let h = esc(text || '');
  h = h.replace(/^###?\s?(.+)$/gm, '<div class="clab-h3">$1</div>');
  h = h.replace(/\*\*(.+?)\*\*/g, '<b>$1</b>');
  h = h.replace(/^\s*[-*]\s+(.+)$/gm, '<div class="clab-li">$1</div>');
  h = h.replace(/\n{2,}/g, '<br><br>').replace(/\n/g, '<br>');
  return h;
}
// Strip foreign tags that other extensions (calendar/weather/status/infoboard) inject into generations.
function cleanLab(t) {
  return String(t || '')
    .replace(/<datetime>[\s\S]*?<\/datetime>/gi, '')
    .replace(/<(\w[\w-]*)\b[^>]*>[\s\S]*?<\/\1>/g, '')
    .replace(/<\/?\w[\w-]*\b[^>]*>/g, '')
    .replace(/^\s*(date|time|weather|status|статус|дата|время|погода)\s*[:：].*$/gim, '')
    .replace(/[ \t]+\n/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

// ---------- isolated generation (reads RP, writes clean report) ----------
const LAB_SYS = `Ты — «Лаборатория совместимости»: отдельный аналитический инструмент (астрология, нумерология, матрица судьбы, таро, тесты) для пары {{user}} и {{char}}. Ты НЕ участник ролевой игры и НЕ озвучиваешь персонажа.
Жёсткие правила:
1. Выдавай только чистый аналитический разбор на русском. НИКАКОГО ролеплея: без действий в звёздочках, без речи от первого лица за персонажа, без продолжения сцены, без диалогов, без блоков комиксов/погоды/статуса/инфоборда и любых тегов.
2. Можешь учитывать их отношения по данному короткому отрывку сцены, но пиши со стороны, как эксперт, и кратко — 1-2 отсылки максимум.
3. Числа и позиции даны и точны — НЕ пересчитывай их. Без вступлений и без вопросов в конце. Разрешён markdown: подзаголовки ## и списки «- ».`;

const TALK_SYS = `Ты — {{char}}. Вы с {{user}} только что в Лаборатории совместимости прошли тесты, гороскопы, таро, матрицу — и теперь разговариваете об этом вдвоём. Это ЖИВОЙ ДИАЛОГ.
Правила:
1. Отвечай ИМЕННО на последнюю реплику {{user}}: поддерживай разговор, отвечай на вопросы, реагируй на шутки и подколы. Если {{user}} сменил тему — иди за ним.
2. Итоги тестов — фон. Упоминай их только когда к слову. НЕ пересказывай результаты заново и НЕ повторяй то, что уже говорил в этом разговоре.
3. Говори в характере {{char}}, своим тоном: 1-3 коротких предложения, по-русски, максимум одно короткое действие.
4. Запрещено: посторонняя сцена и продолжение сюжета, блоки <datetime>, погода, дата, время, статусы, инфоборд, комиксы и любые теги расширений. Не начинай ответ со своего имени.`;

const ENGINES = { main: 'Основная', big: 'Big', medium: 'Medium', small: 'Small' };
// Rough token estimate for the meter (Russian ≈3 chars/token); marked with "≈" everywhere it is shown.
function estTok(s) { return Math.ceil(String(s || '').length / 3); }
function trackSpend(inp, out) { state.spent.tok += estTok(inp) + estTok(out); state.spent.calls += 1; save(); renderEco(); }
// Routes a generation either through the chat's main API (generateRaw) or through an ExtBlocks
// API preset (the "battery": big/medium/small) — cheap models for the lab without touching the RP model.
async function rawGen(sys, prompt, len) {
  const engine = ENGINES[state.engine] ? state.engine : 'small';
  if (engine === 'main') {
    const out = await ctx.generateRaw({ prompt: subst(prompt), systemPrompt: subst(sys), instructOverride: true, responseLength: len });
    trackSpend(subst(sys) + subst(prompt), out);
    return out;
  }
  try {
    const messages = [{ role: 'system', content: subst(sys) }, { role: 'user', content: subst(prompt) }];
    const data = await ApiService.generateBlocks(messages, engine);
    const out = ApiService.extractMessageFromData(data, ApiService.getApiPreset(engine));
    trackSpend(messages.map(m => m.content).join(' '), out);
    return out;
  } catch (e) {
    console.error('[Лаборатория] preset engine error', e);
    toastr.error(`[Лаборатория] Пресет «${ENGINES[engine]}» не ответил — проверь его Connection Profile в ExtBlocks → API Settings, или переключи движок на «Основная».`);
    throw e;
  }
}

// Dialogue variant: real role-based turns so the model answers the LAST user message,
// instead of producing yet another "reaction to the results".
async function rawGenMsgs(messages, len) {
  const engine = ENGINES[state.engine] ? state.engine : 'small';
  const sys = messages.find(m => m.role === 'system')?.content || '';
  const turns = messages.filter(m => m.role !== 'system');
  if (engine === 'main') {
    const flat = turns.map(m => (m.role === 'assistant' ? state.char.name : state.user.name) + ': ' + m.content).join('\n');
    const out = await ctx.generateRaw({ prompt: subst(flat + '\n\nОтветь следующей репликой за ' + state.char.name + ' (только текст реплики).'), systemPrompt: subst(sys), instructOverride: true, responseLength: len });
    trackSpend(subst(sys) + subst(flat), out);
    return out;
  }
  try {
    const msgs = [{ role: 'system', content: subst(sys) }, ...turns.map(m => ({ role: m.role, content: subst(m.content) }))];
    const data = await ApiService.generateBlocks(msgs, engine);
    const out = ApiService.extractMessageFromData(data, ApiService.getApiPreset(engine));
    trackSpend(msgs.map(m => m.content).join(' '), out);
    return out;
  } catch (e) {
    console.error('[Лаборатория] preset engine error', e);
    toastr.error(`[Лаборатория] Пресет «${ENGINES[engine]}» не ответил — проверь его Connection Profile в ExtBlocks → API Settings, или переключи движок на «Основная».`);
    throw e;
  }
}

function rpDigest(maxMsgs = 5, perMsg = 260) {
  try {
    return ctx.chat.filter(m => !m.is_system && m.mes).slice(-maxMsgs)
      .map(m => `${m.is_user ? state.user.name : state.char.name}: ${String(m.mes).replace(/<[^>]*>/g, ' ').replace(/[*_`#>]/g, '').replace(/\s+/g, ' ').trim().slice(0, perMsg)}`)
      .join('\n');
  } catch (e) { return ''; }
}
function charDigest() {
  try {
    const f = ctx.getCharacterCardFields();
    return [f.description, f.personality].filter(Boolean).join(' ').replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim().slice(0, 550);
  } catch (e) { return ''; }
}
// Vibe source for the PERSONA: its description, or (if empty) the user's recent chat lines.
function userDigest() {
  try {
    const desc = String(ctx.powerUserSettings?.persona_description || '').replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();
    if (desc) return desc.slice(0, 550);
  } catch (e) { /* ignore */ }
  try {
    return ctx.chat.filter(m => m.is_user && !m.is_system && m.mes).slice(-6)
      .map(m => String(m.mes).replace(/<[^>]*>/g, ' ').replace(/[*_`#>]/g, '').replace(/\s+/g, ' ').trim().slice(0, 200)).join(' ').slice(0, 550);
  } catch (e) { return ''; }
}
async function labGen(task, len = 320) {
  const promptBody = `Контекст пары (только для понимания, НЕ копируй в ответ):\nПерсонаж: ${charDigest()}\nНедавняя сцена:\n${rpDigest()}\n\nЗАДАЧА:\n${task}`;
  try {
    const out = await rawGen(LAB_SYS, promptBody, len);
    return cleanLab(out);
  } catch (e) {
    console.error('[Лаборатория] generation error', e);
    return '';
  }
}

// ---------- SVG charts ----------
function pol(cx, cy, r, deg) { const a = deg * RAD; return [cx + r * Math.cos(a), cy + r * Math.sin(a)]; }
function octagramSVG(name, M, hue) {
  const S = 250, c = 125, R = 80;
  const D = r22(M.A + M.B + M.C);
  const pts = [[0, M.C, 'Год'], [45, r22(M.C + D), ''], [90, D, 'Назнач.'], [135, r22(D + M.A), ''], [180, M.A, 'День'], [225, r22(M.A + M.B), ''], [270, M.B, 'Месяц'], [315, r22(M.B + M.C), '']];
  const card = [0, 90, 180, 270];
  const poly = (degs) => degs.map(d => pol(c, c, R, d).map(v => v.toFixed(1)).join(',')).join(' ');
  let s = `<svg viewBox="0 0 ${S} ${S}" width="226" height="226" style="color:var(--SmartThemeBodyColor)">`;
  s += `<polygon points="${poly([0, 90, 180, 270])}" fill="none" stroke="${hue}" stroke-width="1" opacity=".5"/>`;
  s += `<polygon points="${poly([45, 135, 225, 315])}" fill="none" stroke="${hue}" stroke-width="1" opacity=".5"/>`;
  for (const [deg, val, label] of pts) {
    const [x, y] = pol(c, c, R, deg), big = card.includes(deg), rad = big ? 15 : 11;
    s += `<circle cx="${x.toFixed(1)}" cy="${y.toFixed(1)}" r="${rad}" fill="${hue}22" stroke="${hue}" stroke-width="1.2"/>`;
    s += `<text x="${x.toFixed(1)}" y="${y.toFixed(1)}" text-anchor="middle" dominant-baseline="central" font-size="${big ? 14 : 12}" font-weight="600" fill="currentColor">${val}</text>`;
    if (label) { const [lx, ly] = pol(c, c, R + (deg === 90 ? 28 : 22), deg); s += `<text x="${lx.toFixed(1)}" y="${ly.toFixed(1)}" text-anchor="middle" dominant-baseline="central" font-size="10" fill="currentColor" opacity=".55">${label}</text>`; }
  }
  s += `<circle cx="${c}" cy="${c}" r="21" fill="${hue}33" stroke="${hue}" stroke-width="1.4"/>`;
  s += `<text x="${c}" y="${c}" text-anchor="middle" dominant-baseline="central" font-size="17" font-weight="700" fill="currentColor">${M.core}</text>`;
  s += `</svg>`;
  return `<figure class="clab-octa">${s}<figcaption>${esc(name)} · ядро ${M.core}, миссия ${M.mission}</figcaption></figure>`;
}
function natalWheelSVG(uN, cN) {
  const S = 320, c = 160, Rout = 150, Rin = 118;
  let s = `<svg viewBox="0 0 ${S} ${S}" width="300" height="300" style="color:var(--SmartThemeBodyColor)">`;
  s += `<circle cx="${c}" cy="${c}" r="${Rout}" fill="none" stroke="var(--SmartThemeBorderColor)" stroke-width="1"/>`;
  s += `<circle cx="${c}" cy="${c}" r="${Rin}" fill="none" stroke="var(--SmartThemeBorderColor)" stroke-width="1"/>`;
  s += `<circle cx="${c}" cy="${c}" r="46" fill="none" stroke="var(--SmartThemeBorderColor)" stroke-width="1" opacity=".5"/>`;
  for (let i = 0; i < 12; i++) {
    const deg = -90 + i * 30;
    const [x1, y1] = pol(c, c, Rin, deg), [x2, y2] = pol(c, c, Rout, deg);
    s += `<line x1="${x1.toFixed(1)}" y1="${y1.toFixed(1)}" x2="${x2.toFixed(1)}" y2="${y2.toFixed(1)}" stroke="var(--SmartThemeBorderColor)" stroke-width=".7" opacity=".7"/>`;
    const [gx, gy] = pol(c, c, (Rin + Rout) / 2, deg + 15);
    s += `<text x="${gx.toFixed(1)}" y="${gy.toFixed(1)}" text-anchor="middle" dominant-baseline="central" font-size="15" fill="currentColor" opacity=".7">${glyph(SIGN_GLYPH[SIGNS[i]])}</text>`;
  }
  const place = (natal, r, color) => {
    const bySign = {};
    for (const p in natal) { const idx = SIGNS.indexOf(natal[p]); if (idx < 0) continue; (bySign[idx] = bySign[idx] || []).push(p); }
    for (const idx in bySign) {
      const arr = bySign[idx], base = -90 + (+idx) * 30 + 15;
      arr.forEach((p, k) => { const off = (k - (arr.length - 1) / 2) * 9; const [px, py] = pol(c, c, r, base + off); s += `<text x="${px.toFixed(1)}" y="${py.toFixed(1)}" text-anchor="middle" dominant-baseline="central" font-size="14" fill="${color}">${glyph(PLANET_GLYPH[p]) || '•'}</text>`; });
    }
  };
  place(cN, 99, '#c47089');
  place(uN, 71, '#6f8fc4');
  s += `<text x="${c}" y="${c}" text-anchor="middle" dominant-baseline="central" font-size="15" fill="currentColor" opacity=".4">${glyph('♡')}</text>`;
  s += `</svg>`;
  const legend = `<div class="clab-legend"><span><i class="clab-dot" style="background:#6f8fc4"></i>${esc(state.user.name)}</span><span><i class="clab-dot" style="background:#c47089"></i>${esc(state.char.name)}</span></div>`;
  return `<div class="clab-diag">${s}${legend}</div>`;
}
function donutSVG(pct, label) {
  const S = 112, c = 56, r = 45, C = 2 * Math.PI * r, off = C * (1 - pct / 100);
  return `<figure class="clab-octa"><svg viewBox="0 0 ${S} ${S}" width="106" height="106" style="color:var(--SmartThemeBodyColor)"><circle cx="${c}" cy="${c}" r="${r}" fill="none" stroke="var(--SmartThemeBorderColor)" stroke-width="8"/><circle cx="${c}" cy="${c}" r="${r}" fill="none" stroke="var(--SmartThemeQuoteColor)" stroke-width="8" stroke-linecap="round" stroke-dasharray="${C.toFixed(1)}" stroke-dashoffset="${off.toFixed(1)}" transform="rotate(-90 ${c} ${c})"/><text x="${c}" y="${c}" text-anchor="middle" dominant-baseline="central" font-size="22" font-weight="600" fill="currentColor">${pct}%</text></svg><figcaption>${esc(label)}</figcaption></figure>`;
}

// ---------- state in chat metadata ----------
const MK = 'compat_lab';
const state = (ctx.chatMetadata[MK] && typeof ctx.chatMetadata[MK] === 'object') ? ctx.chatMetadata[MK] : {};
ctx.chatMetadata[MK] = state;
state.user = state.user || { name: '', birth: '' };
state.char = state.char || { name: '', birth: '' };
state.chem = state.chem || { spark: 50, trust: 50, tension: 10 };
state.quiz = state.quiz || null;
state.texts = state.texts || {};
state.computed = state.computed || null;
state.tarot = state.tarot || null;
state.sessions = state.sessions || [];
state.discussion = state.discussion || [];
state.engine = state.engine || 'small';
state.memory = state.memory || 'reaction'; // что перс узнает после финиша: 'reaction' (только своя реплика) или 'summary' (+ мини-сводка в промпт)
state.spent = state.spent || { tok: 0, calls: 0 }; // примерный расход изолированных вызовов за сессию
state.quizCount = [3, 5, 7, 10].includes(state.quizCount) ? state.quizCount : 5;
state.customTheme = state.customTheme || '';
if (!state.user.name) state.user.name = ctx.name1 || 'Ты';
if (!state.char.name) state.char.name = ctx.name2 || ctx.characters?.[ctx.characterId]?.name || 'Персонаж';
function save() { ctx.chatMetadata[MK] = state; ctx.saveMetadataDebounced(); }

