const $ = (sel) => root.querySelector(sel);
const uname = $('[data-uname]'), ubirth = $('[data-ubirth]'), cname = $('[data-cname]'), cbirth = $('[data-cbirth]');
const resultBox = $('[data-out]'), computedLine = $('[data-computed]'), chemBox = $('[data-chem]'), pairLine = $('[data-pair]');
uname.value = state.user.name; ubirth.value = state.user.birth;
cname.value = state.char.name; cbirth.value = state.char.birth;
[[uname, () => state.user.name = uname.value.trim()], [ubirth, () => state.user.birth = ubirth.value.trim()],
 [cname, () => state.char.name = cname.value.trim()], [cbirth, () => state.char.birth = cbirth.value.trim()]]
  .forEach(([el, fn]) => el.addEventListener('input', () => { fn(); renderPair(); save(); }));

function renderPair() { pairLine.textContent = `${state.user.name || 'Ты'} × ${state.char.name || 'Персонаж'}`; }
function renderChem() {
  const c = state.chem;
  const bar = (icon, label, val, color) => `<div class="clab-bar"><span class="clab-blabel"><i class="fa-solid ${icon}"></i>${label}</span><div class="clab-track"><div class="clab-fill" style="width:${Math.max(0, Math.min(100, val))}%;background:${color};"></div></div><span class="clab-bval">${Math.round(val)}</span></div>`;
  chemBox.innerHTML = bar('fa-heart', 'Искра', c.spark, '#c47089') + bar('fa-handshake', 'Доверие', c.trust, '#5d9a85') + bar('fa-bolt', 'Напряжение', c.tension, '#c39a55');
}
function renderComputed() {
  const cm = state.computed;
  if (!cm) { computedLine.innerHTML = '<span class="clab-placeholder">ещё не рассчитано</span>'; return; }
  computedLine.innerHTML =
    `<span class="clab-chip">${glyph(SIGN_GLYPH[cm.uZ])} ${cm.uZ} · <b>${cm.uL}</b></span>` +
    `<span class="clab-chip">${glyph(SIGN_GLYPH[cm.cZ])} ${cm.cZ} · <b>${cm.cL}</b></span>` +
    `<span class="clab-chip">стихии <b>${cm.elem}%</b></span>` +
    `<span class="clab-chip">нумерология <b>${cm.num}%</b></span>`;
}
function renderEco() { const el = $('[data-eco-spent]'); if (el) el.textContent = String(state.spent.tok); }
