// ---------- compute ----------
function doCompute(silent) {
  const du = parseDate(ubirth.value), dc = parseDate(cbirth.value);
  if (!du || !dc) { if (!silent) toastr.warning('[Лаборатория] Укажи обе даты в формате ДД.ММ.ГГГГ.'); return false; }
  const uZ = zodiacOf(du.d, du.mo), cZ = zodiacOf(dc.d, dc.mo);
  const uL = lifePath(du.d, du.mo, du.y), cL = lifePath(dc.d, dc.mo, dc.y);
  const uM = matrixOf(du.d, du.mo, du.y), cM = matrixOf(dc.d, dc.mo, dc.y);
  const uN = natalAt(du.y, du.mo, du.d), cN = natalAt(dc.y, dc.mo, dc.d);
  const pairArc = r22(uM.core + cM.core);
  state.computed = {
    uZ, cZ, uL, cL, uN, cN,
    uM: { ...uM, coreName: ARCANA[uM.core], missionName: ARCANA[uM.mission] },
    cM: { ...cM, coreName: ARCANA[cM.core], missionName: ARCANA[cM.mission] },
    pairArc, pairArcName: ARCANA[pairArc],
    elem: elementScore(uZ, cZ), num: numerologyScore(uL, cL),
  };
  save(); renderComputed();
  return true;
}
$('[data-compute]').addEventListener('click', () => { if (doCompute(false)) toastr.success('[Лаборатория] Готово: знаки, числа, матрица, натал.'); });

// Vibe-guess a birth date: for the character (card digest) or the persona (description / recent lines).
async function guessDate(isUser) {
  setResult(busyRow(isUser ? 'Подбираю дату по вайбу твоей персоны…' : 'Подбираю дату по характеру…'));
  let out = '';
  try {
    const who = isUser
      ? `Человек (персона игрока по имени ${state.user.name || 'игрок'}). Её вайб (описание персоны или недавние реплики): ${userDigest() || 'данных мало — выбери любую гармоничную дату'}\n\nВыбери для неё одну правдоподобную дату рождения взрослого человека под этот вайб (день, месяц и реалистичный год).`
      : `Персонаж: ${charDigest()}\n\nВыбери для него одну правдоподобную дату рождения (если канон молчит — по характеру).`;
    out = await rawGen('Ты выдаёшь строго одну дату в формате ДД.ММ.ГГГГ и больше ничего.', `${who} Ответь ТОЛЬКО строкой в формате ДД.ММ.ГГГГ.`, 24);
  } catch (e) { console.error(e); }
  const d = parseDate(out || '');
  if (d) {
    const v = `${String(d.d).padStart(2, '0')}.${String(d.mo).padStart(2, '0')}.${d.y}`;
    if (isUser) { ubirth.value = v; state.user.birth = v; } else { cbirth.value = v; state.char.birth = v; }
    save();
    setResult(`<div class="clab-meta"><i class="fa-solid fa-wand-magic-sparkles"></i>Дата ${isUser ? 'твоей персоны' : 'персонажа'} выбрана по вайбу: <b>${esc(v)}</b>. Жми «Рассчитать».</div>`);
  } else setResult(`<div class="clab-meta"><i class="fa-solid fa-triangle-exclamation"></i>Не удалось распознать дату. Впиши вручную.</div>`);
}
$('[data-guess-u]').addEventListener('click', (e) => { e.preventDefault(); e.stopPropagation(); guessDate(true); });
