// ---------- chemistry nudges ----------
function nudge(spark, trust, tension) {
  state.chem.spark = Math.max(0, Math.min(100, state.chem.spark + spark));
  state.chem.trust = Math.max(0, Math.min(100, state.chem.trust + trust));
  state.chem.tension = Math.max(0, Math.min(100, state.chem.tension + tension));
  renderChem(); save();
}

// ---------- quiz (batch of 5; character answers too; many test types) ----------
const QUIZ_CATS = ['Романтика', 'Дружба', 'Страсть', 'Разум'];
const TEST_TYPES = [
  { id: 'love', label: 'Любовь и романтика', icon: 'fa-heart', hint: 'романтика, нежность, как проявляете любовь' },
  { id: 'passion', label: 'Страсть и химия', icon: 'fa-fire', hint: 'влечение, флирт, страсть, телесность' },
  { id: 'trust', label: 'Доверие и дружба', icon: 'fa-handshake', hint: 'доверие, поддержка, дружба внутри пары' },
  { id: 'comm', label: 'Общение', icon: 'fa-comments', hint: 'как общаетесь, слушаете, язык любви' },
  { id: 'conflict', label: 'Конфликты', icon: 'fa-bolt', hint: 'ссоры, ревность, примирение, стиль конфликта' },
  { id: 'future', label: 'Быт и будущее', icon: 'fa-house', hint: 'быт, деньги, планы, совместное будущее' },
  { id: 'values', label: 'Ценности и взгляды', icon: 'fa-scale-balanced', hint: 'приоритеты, мораль, что важно в жизни' },
  { id: 'mix', label: 'Микс аспектов', icon: 'fa-shuffle', hint: 'смесь: любовь, быт, конфликт, страсть, будущее — по вопросу на аспект' },
];
function letterIdx(s) { const m = String(s).trim().toUpperCase().match(/[A-DА-Г]/); if (!m) return -1; const lat = 'ABCD'.indexOf(m[0]); return lat >= 0 ? lat : 'АБВГ'.indexOf(m[0]); }
function parseQuizBatch(raw, count = 8) {
  const lines = raw.split('\n').map(s => s.trim()).filter(Boolean);
  const theme = (lines.find(l => /^ТЕМА\s*[:.]/i.test(l)) || '').replace(/^ТЕМА\s*[:.]/i, '').trim();
  const questions = [];
  for (let n = 1; n <= count; n++) {
    const qLine = lines.find(l => new RegExp('^ВОПРОС\\s*' + n + '\\s*[:.]', 'i').test(l));
    if (!qLine) continue;
    const optLines = lines.filter(l => new RegExp('^' + n + '\\s*[A-DА-Г]\\s*\\|', 'i').test(l)).slice(0, 4);
    if (optLines.length < 4) continue;
    const opts = optLines.map(l => { const p = l.split('|'); const cat = (p[1] || '').trim(); return { cat: QUIZ_CATS.includes(cat) ? cat : 'Разум', pts: Math.max(0, Math.min(3, parseInt(p[2]) || 0)), text: (p.slice(3).join('|') || '').trim() }; });
    const charLine = lines.find(l => new RegExp('^' + n + '\\s*(ВЫБОР|CHAR)\\s*\\|', 'i').test(l));
    let charPick = -1, charReason = '';
    if (charLine) { const p = charLine.split('|'); charPick = letterIdx(p[1] || ''); charReason = (p.slice(2).join('|') || '').trim(); }
    questions.push({ text: qLine.replace(new RegExp('^ВОПРОС\\s*' + n + '\\s*[:.]', 'i'), '').trim(), opts, charPick, charReason });
  }
  return { theme, questions };
}
async function quizEntry() {
  const q = state.quiz;
  if (q && q.questions && q.q < q.total) { renderQuizQuestion(); return; }
  quizMenu();
}
function quizMenu() {
  const escAttr = (s) => esc(s).replace(/"/g, '&quot;');
  let html = `<div class="clab-h2"><i class="fa-solid fa-clipboard-question"></i>Выбери тест</div>`;
  if (state.texts.quiz) html += `<div class="clab-meta"><i class="fa-solid fa-clock-rotate-left"></i>Прошлый: «${esc(state.texts.quiz.theme)}» — ${state.texts.quiz.total}% · <span data-viewlast style="cursor:pointer;text-decoration:underline">показать</span></div>`;
  html += `<div class="clab-cntrow"><span style="opacity:.6">Вопросов:</span>` + [3, 5, 7, 10].map(n => `<button type="button" class="clab-cnt${state.quizCount === n ? ' clab-on' : ''}" data-cnt="${n}">${n}</button>`).join('') + `</div>`;
  html += `<div class="clab-testgrid">`;
  TEST_TYPES.forEach(t => { html += `<button type="button" class="clab-btn" data-ttype="${t.id}"><i class="fa-solid ${t.icon}"></i>${t.label}</button>`; });
  html += `</div>`;
  html += `<div class="clab-customrow"><input type="text" class="text_pole" data-ctheme placeholder="Своя тема: ревность, готовка, бывшие, киновкусы…" value="${escAttr(state.customTheme)}"><button type="button" class="clab-btn clab-primary clab-icon" data-cstart title="Сгенерировать тест по своей теме"><i class="fa-solid fa-play"></i></button></div>`;
  setResult(html);
  resultBox.querySelectorAll('[data-cnt]').forEach(b => b.addEventListener('click', (e) => { e.preventDefault(); e.stopPropagation(); state.quizCount = +b.dataset.cnt; save(); quizMenu(); }));
  resultBox.querySelectorAll('[data-ttype]').forEach(b => b.addEventListener('click', (e) => { e.preventDefault(); e.stopPropagation(); quizStart(TEST_TYPES.find(t => t.id === b.dataset.ttype) || TEST_TYPES[0]); }));
  const ctheme = resultBox.querySelector('[data-ctheme]');
  const startCustom = () => {
    const v = (ctheme.value || '').trim();
    if (!v) { toastr.warning('[Лаборатория] Сначала впиши тему теста.'); ctheme.focus(); return; }
    state.customTheme = v; save();
    quizStart({ id: 'custom', label: v, hint: 'тема задана игроком — раскрой именно её применительно к их паре' });
  };
  resultBox.querySelector('[data-cstart]')?.addEventListener('click', (e) => { e.preventDefault(); e.stopPropagation(); startCustom(); });
  if (ctheme) ctheme.addEventListener('keydown', (e) => { if (e.key === 'Enter') { e.preventDefault(); e.stopPropagation(); startCustom(); } });
  bindAction('viewlast', renderQuizResult);
}
async function quizStart(tt) {
  const count = [3, 5, 7, 10].includes(state.quizCount) ? state.quizCount : 5;
  setResult(busyRow(`Генерирую тест из ${count} вопросов…`));
  let fmt = `ТЕМА: <короткая тема>
ВОПРОС1: <вопрос>
1A|<категория>|<очки>|<вариант>
1B|<категория>|<очки>|<вариант>
1C|<категория>|<очки>|<вариант>
1D|<категория>|<очки>|<вариант>
1ВЫБОР|<буква A/B/C/D>|<почему {{char}} так выбрал>`;
  for (let n = 2; n <= count; n++) fmt += `\nВОПРОС${n}: <вопрос> (далее ${n}A|${n}B|${n}C|${n}D|${n}ВЫБОР)`;
  const task = `Составь тест на совместимость пары {{user}} и {{char}} по теме «${tt.label}» (${tt.hint}). Ровно ${count} вопросов, у каждого 4 варианта. Для КАЖДОГО вопроса также реши, какой вариант выбрал бы сам {{char}} исходя из своего характера, и дай очень короткую причину (до 8 слов). Вопросы обращены к {{user}}, это викторина — НЕ ролеплей (без действий и без речи за персонажа в тексте вопросов). Выведи СТРОГО в этом формате и больше ничего:
${fmt}
Категория ∈ {Романтика, Дружба, Страсть, Разум}, очки — целое 0..3.`;
  const raw = await labGen(task, Math.min(2600, 160 + 220 * count));
  const parsed = parseQuizBatch(raw, count);
  if (parsed.questions.length < Math.min(3, count)) { setResult(busyRow('Не разобрал формат теста.') + actionRow('retry', 'fa-rotate', 'Ещё раз')); bindAction('retry', () => quizStart(tt)); return; }
  state.quiz = { type: tt.id, theme: parsed.theme || tt.label, total: parsed.questions.length, q: 0, questions: parsed.questions, userPicks: [], scores: { Романтика: 0, Дружба: 0, Страсть: 0, Разум: 0 }, matches: 0 };
  save();
  renderQuizQuestion();
}
function renderQuizQuestion() {
  const q = state.quiz, idx = q.q, cur = q.questions[idx];
  if (q.userPicks[idx] != null) { renderReveal(idx); return; }
  let html = `<div class="clab-h2"><i class="fa-solid fa-clipboard-question"></i>${esc(q.theme)} · вопрос ${idx + 1}/${q.total}</div><div class="clab-q">${esc(cur.text)}</div><div class="clab-opts">`;
  cur.opts.forEach((o, i) => { html += `<button type="button" class="clab-opt" data-opt="${i}"><span class="clab-letter">${'АБВГ'[i]}</span><span>${esc(o.text)}</span></button>`; });
  html += `</div>`;
  setResult(html);
  resultBox.querySelectorAll('[data-opt]').forEach(btn => btn.addEventListener('click', (e) => { e.preventDefault(); e.stopPropagation(); pickAnswer(idx, +btn.dataset.opt); }));
}
function pickAnswer(idx, userIdx) {
  const q = state.quiz, cur = q.questions[idx], o = cur.opts[userIdx];
  q.userPicks[idx] = userIdx;
  q.scores[o.cat] = (q.scores[o.cat] || 0) + o.pts;
  const match = userIdx === cur.charPick;
  if (match) q.matches = (q.matches || 0) + 1;
  nudge(match ? 2 : 0, match ? 2 : -1, match ? -1 : 2);
  save();
  renderReveal(idx);
}
function renderReveal(idx) {
  const q = state.quiz, cur = q.questions[idx], userIdx = q.userPicks[idx];
  const match = userIdx === cur.charPick;
  let html = `<div class="clab-h2"><i class="fa-solid fa-clipboard-question"></i>${esc(q.theme)} · вопрос ${idx + 1}/${q.total}</div><div class="clab-q">${esc(cur.text)}</div><div class="clab-opts">`;
  cur.opts.forEach((o, i) => {
    const you = i === userIdx, ch = i === cur.charPick;
    let cls = 'clab-opt clab-rev', tag = '';
    if (you && ch) { cls += ' clab-both'; tag = `<span class="clab-pick">оба</span>`; }
    else if (you) { cls += ' clab-you'; tag = `<span class="clab-pick">ты</span>`; }
    else if (ch) { cls += ' clab-char'; tag = `<span class="clab-pick">${esc(state.char.name)}</span>`; }
    html += `<div class="${cls}"><span class="clab-letter">${'АБВГ'[i]}</span><span>${esc(o.text)}</span>${tag}</div>`;
  });
  html += `</div>`;
  html += `<div class="clab-meta">${match ? '<i class="fa-solid fa-check"></i>Совпали' : '<i class="fa-solid fa-arrows-left-right"></i>Разошлись'}${cur.charReason ? ` · ${esc(state.char.name)}: ${esc(cur.charReason)}` : ''}</div>`;
  html += actionRow('next', idx + 1 < q.total ? 'fa-arrow-right' : 'fa-flag-checkered', idx + 1 < q.total ? 'Дальше' : 'Подвести итог');
  setResult(html);
  bindAction('next', () => { state.quiz.q += 1; save(); if (state.quiz.q < state.quiz.total) renderQuizQuestion(); else quizVerdict(); });
}
async function quizVerdict() {
  const q = state.quiz;
  const sum = QUIZ_CATS.reduce((a, c) => a + (q.scores[c] || 0), 0);
  const align = Math.round((q.matches || 0) / q.total * 100);
  const total = clampPct(align * 0.65 + (40 + sum * 4) * 0.35);
  setResult(busyRow('Подвожу итог теста…'));
  const verdict = await labGen(`Итог теста на совместимость «${q.theme}» для пары {{user}} и {{char}} (отвечали независимо, ответы {{char}} выбраны по его характеру). Совпадений: ${q.matches || 0} из ${q.total} (${align}%). Очки по категориям: ${QUIZ_CATS.map(c => c + ' ' + (q.scores[c] || 0)).join(', ')}. Итоговый балл: ${total}%. Дай короткий аналитический вердикт ведущего (2-3 предложения): что значит такой уровень совпадений и где паре расти. Без ролеплея.`, 220);
  state.texts.quiz = { theme: q.theme, total, align, matches: q.matches || 0, totalQ: q.total, scores: { ...q.scores }, verdict };
  if (!state.sessionQuiz) state.sessionQuiz = [];
  state.sessionQuiz.push({ theme: q.theme, total, align });
  nudge(total >= 70 ? 3 : 0, total >= 70 ? 2 : -1, total >= 70 ? -2 : 2);
  state.quiz = null; save();
  renderQuizResult();
}
function renderQuizResult() {
  const r = state.texts.quiz;
  const diag = (r.align != null) ? `<div class="clab-diag"><div class="clab-numpair">${donutSVG(r.total, 'итог')}${donutSVG(r.align, 'совпадения')}</div></div>` : '';
  const sub = (r.matches != null ? `Совпало ${r.matches}/${r.totalQ} · ` : '') + QUIZ_CATS.map(c => c + ': ' + (r.scores[c] || 0)).join(' · ');
  setResult(`<div class="clab-h2"><i class="fa-solid fa-clipboard-question"></i>Итог «${esc(r.theme)}»${r.align == null ? ': ' + r.total + '%' : ''}</div>${diag}<div class="clab-meta">${sub}</div><div style="margin-top:10px">${mdLite(r.verdict)}</div>` + actionRow('newquiz', 'fa-list-check', 'Другой тест'));
  bindAction('newquiz', quizMenu);
}

