      task: `Разбор натальных карт и синастрии пары (расчёт на полдень UTC без времени рождения — упомяни это одной фразой). {{user}}: ${fmt(cm.uN)}. {{char}}: ${fmt(cm.cN)}. Совместимость стихий солнц: ${cm.elem}%. Дай: ## карта каждого кратко (Солнце/Луна/Венера/Марс — как любит и как ведёт себя в конфликте), ## синастрия (Солнце×Солнце, Луна×Луна, Венера×Марс), формула пары одной строкой. 150-190 слов.`,
    };
  }
  return {
    head: 'Гороскоп на сегодня', icon: 'fa-moon', len: 340,
    diagram: `<div class="clab-diag"><div class="clab-numpair"><div class="clab-signbig">${glyph(SIGN_GLYPH[cm.uZ])}<span>${esc(state.user.name)} · ${cm.uZ}</span></div><i class="fa-solid fa-heart" style="opacity:.4;font-size:15px;color:var(--SmartThemeQuoteColor)"></i><div class="clab-signbig">${glyph(SIGN_GLYPH[cm.cZ])}<span>${esc(state.char.name)} · ${cm.cZ}</span></div></div></div>`,
    task: `Гороскоп совместимости пары на сегодня (${new Date().toLocaleDateString('ru-RU')}): {{user}} — ${cm.uZ}, {{char}} — ${cm.cZ}. Учитывай недавнюю сцену, сошлись на один реальный момент. Дай: общий вайб дня, любовь и искра, зона риска, совет дня, удачное число. 110-150 слов, тон лёгкой астроколонки, но это разбор, а не ролеплей.`,
  };
}
async function station(kind) {
  if (kind === 'quiz') { await quizEntry(); return; }
  if (kind === 'tarot') { await tarotEntry(); return; }
  if (!needComputed()) return;
  await runStation(kind, false);
}
async function runStation(kind, force) {
  const cfg = stationConfig(kind, state.computed);
  const header = `<div class="clab-h2"><i class="fa-solid ${cfg.icon}"></i>${cfg.head}</div>`;
  if (state.texts[kind] && !force) {
    setResult(header + cfg.diagram + mdLite(state.texts[kind]) + actionRow('regen', 'fa-rotate', 'Обновить разбор'));
    bindAction('regen', () => runStation(kind, true));
    return;
  }
  setResult(header + cfg.diagram + busyRow('Готовлю разбор…'));
  const text = await labGen(cfg.task, cfg.len);
  if (text) { state.texts[kind] = text; save(); }
  setResult(header + cfg.diagram + (text ? mdLite(text) : '<div class="clab-meta">Пусто — попробуй обновить.</div>') + actionRow('regen', 'fa-rotate', 'Обновить разбор'));
  bindAction('regen', () => runStation(kind, true));
}
root.querySelectorAll('[data-st]').forEach(b => b.addEventListener('click', (e) => { e.preventDefault(); e.stopPropagation(); station(b.dataset.st); }));

// ---------- tarot (cached) ----------
function tarotCardsHtml(cards) {
  const base = 'https://commons.wikimedia.org/wiki/Special:FilePath/';
  let h = '<div class="clab-h2"><i class="fa-solid fa-clone"></i>Расклад на пару</div><div class="clab-tarot-row">';
  cards.forEach(p => { h += `<figure class="clab-tcard${p.rev ? ' rev' : ''}"><img src="${base}${p.file}?width=160" alt="${esc(p.name)}" loading="lazy"><figcaption><b>${esc(p.pos)}</b><br>${esc(p.name)}${p.rev ? ' · перев.' : ''}</figcaption></figure>`; });
  return h + '</div>';
}
async function tarotEntry() {
  if (state.tarot && state.texts.tarot) { renderTarot(state.tarot.cards, state.texts.tarot.reading); return; }
  await drawTarot();
}
function renderTarot(cards, reading) {
  setResult(tarotCardsHtml(cards) + (reading ? `<div style="margin-top:8px">${mdLite(reading)}</div>` : '') + actionRow('redraw', 'fa-rotate', 'Новый расклад'));
  bindAction('redraw', drawTarot);
}
async function drawTarot() {
  const POS = ['Прошлое', 'Настоящее', 'Будущее'];
  const deck = TAROT_CARDS.slice(), picks = [];
  for (let i = 0; i < 3; i++) { const k = Math.floor(Math.random() * deck.length); const c = deck.splice(k, 1)[0]; picks.push({ pos: POS[i], name: c[0], file: c[1], rev: Math.random() < 0.3 }); }
  state.tarot = { date: new Date().toLocaleDateString('ru-RU'), cards: picks }; save();
  setResult(tarotCardsHtml(picks) + busyRow('Толкую расклад…'));
  const cardsList = picks.map(p => `${p.pos}: ${p.name}${p.rev ? ' (перевёрнутая)' : ''}`).join('; ');
  const reading = await labGen(`Истолкуй уже вытянутый расклад таро на пару {{user}} и {{char}} (карты не меняй): ${cardsList}. Дай: ## по карте на позицию (что значит для их отношений; перевёрнутая = заблокированная/искажённая энергия), ## общий сюжет от прошлого к будущему, совет. Пиши как профессиональный таролог-аналитик, 150-200 слов. Без ролеплея и без речи за персонажа.`, 440);
  state.texts.tarot = { cards: cardsList, reading }; save();
  renderTarot(picks, reading);
}

// ---------- finish ----------
function buildSummary() {
  const parts = [];
  if (state.computed) parts.push(`${state.user.name} (${state.computed.uZ}, число ${state.computed.uL}) × ${state.char.name} (${state.computed.cZ}, число ${state.computed.cL})`);
  const c = state.chem; parts.push(`Химия: искра ${Math.round(c.spark)}, доверие ${Math.round(c.trust)}, напряжение ${Math.round(c.tension)}`);
  if (state.sessionQuiz?.length) parts.push('Тесты: ' + state.sessionQuiz.map(q => `${q.theme} ${q.total}%`).join('; '));
  if (state.computed) parts.push(`Стихии ${state.computed.elem}%, нумерология ${state.computed.num}%, аркан пары «${state.computed.pairArcName}»`);
  if (state.tarot) parts.push('Таро: ' + state.tarot.cards.map(c => c.name + (c.rev ? ' (перев.)' : '')).join(' / '));
  const overall = state.computed
    ? clampPct((c.spark + c.trust) / 2 * 0.45 + state.computed.elem * 0.2 + state.computed.num * 0.15 + (state.sessionQuiz?.length ? (state.sessionQuiz.reduce((a, q) => a + q.total, 0) / state.sessionQuiz.length) : 60) * 0.2)
    : clampPct((c.spark + c.trust) / 2);
  return { overall, line: parts.join(' · ') };
}
function postSystemMessage(text) { const m = { name: 'Лаборатория', is_user: false, is_system: true, mes: text, extra: { isSmallSys: true } }; ctx.chat.push(m); ctx.addOneMessage(m); }
// Ultra-compact model-facing digest (hard cap ~220 chars ≈ 60-80 tokens) for the 'summary' memory mode.
function miniSummary(sum) {
  const bits = [];
  if (state.computed) bits.push(`${state.user.name} (${state.computed.uZ}) × ${state.char.name} (${state.computed.cZ})`);
  if (state.sessionQuiz?.length) bits.push('тесты: ' + state.sessionQuiz.map(q => `${q.theme} ${q.total}%`).join(', '));
  if (state.tarot) bits.push('таро: ' + state.tarot.cards.map(c => c.name).join('/'));
  const s = `Итог Лаборатории совместимости: ${sum.overall}%. ` + bits.join('; ');
  return s.length > 220 ? s.slice(0, 217) + '…' : s;
}
// 'reaction' (default): record is is_system — ST never sends it to the model, zero tokens.
// 'summary': the model sees only the capped miniSummary as mes; the pretty full record stays
// visible to the user via extra.display_text. Full station texts NEVER leave metadata either way.
function postRecord(recordText, sum) {
  if (state.memory === 'summary') {
    const m = { name: 'Лаборатория', is_user: false, is_system: false, mes: miniSummary(sum), extra: { isSmallSys: true, type: 'narrator', display_text: recordText } };
    ctx.chat.push(m); ctx.addOneMessage(m);
  } else {
    postSystemMessage(recordText);
  }
}
function postCharMessage(text) { const m = { name: state.char.name, is_user: false, is_system: false, mes: text, extra: {} }; ctx.chat.push(m); ctx.addOneMessage(m); }
function postUserMessage(text) { const m = { name: state.user.name, is_user: true, is_system: false, mes: text, extra: {} }; ctx.chat.push(m); ctx.addOneMessage(m); }

// Character dialogue turn, generated in isolation: real chat roles, results only as background.
async function charTalk() {
  const sum = buildSummary();
  const sys = `${TALK_SYS}\n\nКто такой {{char}}: ${charDigest()}\nИтоги сессии (фон, не пересказывать): ${sum.overall}% — ${sum.line}`;
  const msgs = [
    { role: 'system', content: sys },
    { role: 'user', content: `[${state.user.name} показывает тебе итоги сессии лаборатории и ждёт твоей живой реакции]` },
  ];
  for (const m of (state.discussion || []).slice(-12)) msgs.push({ role: m.who === 'user' ? 'user' : 'assistant', content: m.text });
  try {
    let reply = cleanLab(await rawGenMsgs(msgs, 240));
    const pfx = state.char.name + ':';
    if (reply.toLowerCase().startsWith(pfx.toLowerCase())) reply = reply.slice(pfx.length).trim();
    return reply;
  } catch (e) { console.error('[Лаборатория] talk error', e); return ''; }
}

// ---- in-widget discussion: play out a short conversation with the character, then send it to chat ----
async function openDiscussion() {
  if (!(state.discussion && state.discussion.length)) {
    state.discussion = [];
    renderDiscussion(true);
    const opening = await charTalk();
    state.discussion.push({ who: 'char', text: opening || '…' });
    save();
  }
  renderDiscussion(false);
}
function renderDiscussion(loading) {
  let html = `<div class="clab-h2"><i class="fa-solid fa-comments"></i>Разговор с ${esc(state.char.name)}</div><div class="clab-chat">`;
  (state.discussion || []).forEach(m => { html += `<div class="clab-msg clab-msg-${m.who}"><b>${m.who === 'user' ? esc(state.user.name) : esc(state.char.name)}</b>${esc(m.text)}</div>`; });
  if (loading) html += `<div class="clab-msg clab-msg-char"><i class="fa-solid fa-spinner fa-spin"></i></div>`;
  const dTok = estTok((state.discussion || []).map(m => m.text).join(' '));
  html += `</div><div class="clab-chatbar"><input type="text" class="text_pole" data-dinput placeholder="Ответь ${esc(state.char.name)}…"${loading ? ' disabled' : ''}><button type="button" class="clab-btn clab-primary clab-icon" data-dsend><i class="fa-solid fa-paper-plane"></i></button></div>` + actionRow('dcommit', 'fa-share-from-square', `Перенести разговор в чат и закрыть (≈${dTok} ток. в историю)`);
  setResult(html);
  const inp = resultBox.querySelector('[data-dinput]');
  const send = async () => {
    const v = (inp.value || '').trim(); if (!v) return;
    state.discussion.push({ who: 'user', text: v }); save();
    renderDiscussion(true);
    const reply = await charTalk();
    state.discussion.push({ who: 'char', text: reply || '…' }); save();
    renderDiscussion(false);
  };
  resultBox.querySelector('[data-dsend]')?.addEventListener('click', (e) => { e.preventDefault(); e.stopPropagation(); send(); });
  if (inp) { inp.addEventListener('keydown', (e) => { if (e.key === 'Enter') { e.preventDefault(); e.stopPropagation(); send(); } }); if (!loading) inp.focus(); }
  bindAction('dcommit', () => finishSession(true));
}

// ---- finish: clean record + the character's on-topic reaction (or the whole discussion) committed to chat ----
async function finishSession(useDiscussion) {
  const sum = buildSummary();
  const date = new Date().toLocaleDateString('ru-RU');
  const record = `Лаборатория совместимости (${date}) — итог сессии {{user}} × {{char}}: ${sum.overall}%. ${sum.line}`;
  state.sessions.push({ date, overall: sum.overall, line: sum.line });
  const discussion = (useDiscussion && state.discussion && state.discussion.length) ? state.discussion.slice() : null;
  let reaction = '';
  if (!discussion) { toastr.info('[Лаборатория] Персонаж реагирует на итоги…'); reaction = await charTalk(); }
  state.sessionQuiz = []; state.discussion = []; state.spent = { tok: 0, calls: 0 };
  try { await ctx.saveMetadata?.(); } catch (e2) { save(); }
  try { await popup.completeAffirmative(); } catch (e2) { /* ignore */ }
  try {
    postRecord(subst(record), sum);
    if (discussion) { for (const m of discussion) { if (m.who === 'user') postUserMessage(m.text); else postCharMessage(m.text); } }
    else if (reaction) { postCharMessage(reaction); }
    await ctx.saveChat();
  } catch (e2) { console.error('[Лаборатория] commit error', e2); toastr.error('[Лаборатория] Не удалось записать в чат.'); }
}
$('[data-discuss]').addEventListener('click', (e) => { e.preventDefault(); e.stopPropagation(); openDiscussion(); });
$('[data-finish]').addEventListener('click', (e) => { e.preventDefault(); e.stopPropagation(); finishSession(false); });

