// ---------- installer: пункт «Лаборатория совместимости» в волшебной палочке (#extensionsMenu) ----------
// Блок настроен на user_message + char_message c period 1, поэтому отрабатывает на первой же реплике
// в чате и вешает пункт меню. Повторные срабатывания дёшевы — ранний выход, если пункт уже на месте.
// Кнопка переживает смену чата (это глобальный DOM), а после перезагрузки ST её вернёт первое сообщение.
(function installWand() {
    const menu = document.getElementById('extensionsMenu');
    if (!menu) return;
    if (document.getElementById('clab_wand_item')) { window.__clabWandInstalled = true; return; }
    const item = document.createElement('div');
    item.id = 'clab_wand_item';
    item.className = 'list-group-item flex-container flexGap5 interactable';
    item.tabIndex = 0;
    item.title = 'Открыть Лабораторию совместимости';
    item.innerHTML = '<div class="fa-fw fa-solid fa-flask extensionsMenuExtensionButton" title="Лаборатория совместимости"></div><span>Лаборатория совместимости</span>';
    const open = (e) => {
        if (e) { e.preventDefault(); e.stopPropagation(); }
        try { (window.jQuery || window.$)('#extensionsMenu').fadeOut(200); } catch (err) { menu.style.display = 'none'; }
        Promise.resolve(window.__clabOpen()).catch(err => console.error('[Лаборатория] open error', err));
    };
    item.addEventListener('click', open);
    item.addEventListener('keydown', (e) => { if (e.key === 'Enter' || e.key === ' ') { open(e); } });
    menu.appendChild(item);
    window.__clabWandInstalled = true;
})();
